// Screamadelica — Primal Scream (1991)
// Generated by tools/cover-converter.html
// Pixel data: 64×64 RGB encoded as a compact hex string

export const meta = { title: 'Screamadelica', artist: 'Primal Scream', year: 1991 };

const HEX = '';

export function draw(d) {
  for (let i = 0; i < 4096; i++) {
    const o = i * 6;
    d.setPixel(
      i % 64,
      Math.floor(i / 64),
      parseInt(HEX.slice(o,     o + 2), 16),
      parseInt(HEX.slice(o + 2, o + 4), 16),
      parseInt(HEX.slice(o + 4, o + 6), 16),
    );
  }
}
